esqlQuery.esql:
FROM logs-azure.activity.otel-*
// Restrict to Azure Activity Logs (ServiceHealth category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "ServiceHealth"
// Incident type indicates active Azure platform outage (vs Maintenance, Informational)
| WHERE azure.servicehealth.incident.type == "Incident"
// Active state — incident in progress; optionally include Resolved for awareness
| WHERE azure.servicehealth.state == "Active"
// Exclude synthetic test events if present
| WHERE COALESCE(azure.servicehealth.is_synthetic, false) == false
| STATS event_count = COUNT(*), services = VALUES(azure.servicehealth.service), regions = VALUES(azure.servicehealth.region) BY azure.servicehealth.tracking.id, azure.servicehealth.title
| SORT event_count DESC
| LIMIT 20
